    const int64_t *stride = attrs->GetAttrPointer<int64_t>(0);
    tiling.set_strideD(stride[0]);
    tiling.set_strideH(stride[1]);
    tiling.set_strideW(stride[2]);
    // padding
    const int64_t *padding = attrs->GetAttrPointer<int64_t>(1);
    tiling.set_padD(padding[0]);
    tiling.set_padH(padding[1]);
    tiling.set_padW(padding[2]);
    // output_padding
    const int64_t *output_padding = attrs->GetAttrPointer<int64_t>(2);
    tiling.set_outputPadD(output_padding[0]);
    tiling.set_outputPadH(output_padding[1]);
    tiling.set_outputPadW(output_padding[2]);
    // groups
    tiling.set_groups(static_cast<uint32_t>(attrs->GetAttrPointer<int64_t>(3)[0]));
    // dilation
    const int64_t *dilation = attrs->GetAttrPointer<int64_t>(4);
    tiling.set_dilationD(dilation[0]);
    tiling.set_dilationH(dilation[1]);
    tiling.set_dilationW(dilation[2]);

    // Compute output spatial size (for each spatial dim)
    auto compOut = [](uint32_t inSize, uint32_t kSize, uint32_t stride, uint32_t pad, uint32_t dilation, uint32_t outPad) -> uint32_t {
        return (inSize - 1) * stride - 2 * pad + dilation * (kSize - 1) + outPad + 1;
    };
    tiling.set_outD(compOut(tiling.inD(), tiling.kD(), tiling.strideD(), tiling.padD(), tiling.dilationD(), tiling.outputPadD()));
    tiling.set_outH(compOut(tiling.inH(), tiling.kH(), tiling.strideH(), tiling.padH(), tiling.dilationH(), tiling.outputPadH()));
    tiling.set_outW(compOut(tiling.inW(), tiling.kW(), tiling.strideW(), tiling.padW(), tiling.dilationW(), tiling.outputPadW()));

    // Total output elements per batch: COut * outD * outH * outW
    uint32_t outElemsPerBatch = tiling.COut() * tiling.outD() * tiling.outH() * tiling.outW();
    uint32_t totalOutElems = tiling.N() * outElemsPerBatch;

    // Determine tile size: aim for about UB_BUDGET_FLOATS floats of output, plus input and weight tiles
    // Simple heuristic: tile over output spatial positions, each tile covers a small output volume.
    uint32_t tileOutputSize = std::min(outElemsPerBatch, UB_BUDGET_FLOATS);
